        THE_CURRENT_THEORY_STATES_THAT_THE_SOLUTION_MAY                               = 6899,  -- The current theory states that the solution may lie in our attack frequency.
        REMEMBER_THAT_A_BATTLE_IS_NOT_WON_ONLY                                        = 6900,  -- Remember that a battle is not won only by the sword. You must also cure wounds from time to time. Keep your eye on the enemy, and react as the occasion demands.
