        ANOTHER_JOB_WELL_DONE_THERE_S_NOTHING_LIKE                                    = 8991,  -- Another job well done. There's nothing like the satisfaction of completing an order.
        ESPECIALLY_SOMETHING_AS_SPECIAL_AS_A_PIECE_OF                                 = 8992,  -- Especially something as special as a piece of magus armor. You must be pretty pleased yourself. Although your face says, Why the bizarre collection of materials?
        MAGUS_ARMOR_IS_DESIGNED_TO_BRING_YOUR_COMBAT                                  = 8993,  -- Magus armor is designed to bring your combat to a new level.
