        I_LL_BE_HELPING_THE_PROFESSOR_OUT_WITH                                        = 12759,  -- I'll be helping the professor out with his experiment.
        ALL_YOU_HAVE_TO_DO_IS_KEEP_US                                                 = 12760,  -- All you have to do is keep us alive while we're collecting the dataru.
