        GETTING_MARRIED_IS_A_SERIOUS_THING_BUT_I                                      = 12804,  -- Getting married is a serious thing, but I don't think I'm ready yet. I'm still the same, weak boy that got his butt kicked on the Ballista courts back at boarding school.
        BEFORE_I_EVEN_TRY_TO_PROVE_TO_MIKI                                            = 12805,  -- Before I even try to prove to Miki that I can protect her, I have to prove to myself that I can.
        SEE_I_KNOW_WHAT_I_M_DOING_I                                                   = 12806,  -- See? I know what I'm doing! I just wish Miki understood as well...
        I_MEAN_I_CAN_SEE_WHY_SHE_IS                                                   = 12807,  -- I mean, I can see why she is worried and all, but I didn't think she would be so unreasonable!
