        ULP_YOU_GUYS_HAVEN_T_BEEN_WAITING_TOO                                         = 12825,  -- Ulp! You guys haven't been waiting too long for me, I hope.
        AHEM_I_APOLOGIZE_DEEPLY_FOR_MY_DELAYED_ARRIVAL                                = 12826,  -- Ahem! I apologize deeply for my delayed arrival, and humbly beg your forgiveness.
